let output = [];

for (const item of items) {

  // ignora queries sem resultado
  if (!item.json.related_queries) continue;

  const related = item.json.related_queries;

  // TOP: pula 1ª, pega 2ª; pula 3ª, pega 4ª...
  const top = (related.top || [])
    .slice(0, 14)
    .filter((_, index) => index % 2 === 1)
    .map(q => ({
      tipo: "top",
      termo: q.query,
      interesse: q.extracted_value ?? q.value,
      origem: item.json.search_parameters.q
    }));

  // RISING normal
  const rising = (related.rising || [])
    .slice(0, 7)
    .map(q => ({
      tipo: "rising",
      termo: q.query,
      interesse: q.extracted_value ?? q.value,
      origem: item.json.search_parameters.q
    }));

  output.push(...top, ...rising);
}

return output;

// 1. TRAVA DE SEGURANÇA
if ($runIndex > 0) return [];

// 2. CAPTURA CONSOLIDADA
const noticias = [];
const paa = [];
const trends = [];

const todosOsItens = $input.all();

todosOsItens.forEach(item => {
  const d = item.json;

  // Notícias (percorre array interno)
  if (d.noticias && Array.isArray(d.noticias)) {
    d.noticias.forEach(n => noticias.push(n));
  }

  // Perguntas PAA (percorre array interno)
  if (d.paa && Array.isArray(d.paa)) {
    d.paa.forEach(q => paa.push({ question: q }));
  }

  // Trends (percorre array interno)
  if (d.trends && Array.isArray(d.trends)) {
    d.trends.forEach(t => trends.push({ termo: t }));
  }
});

// 3. FUNÇÕES DE FORMATAÇÃO
const formatarLista = (lista) => {
  if (!lista.length) return "<p style='color:#666;'>Sem dados disponíveis no momento.</p>";
  return `<ul style="padding-left: 15px; line-height:1.6; margin:0;">
    ${lista.map(i => `<li style="margin-bottom:6px; padding:4px 8px; background:#fee2e2; border-radius:5px; display:inline-block; margin-right:6px;">${i.termo || i.question}</li>`).join("")}
  </ul>`;
};

const formatarNoticias = (lista) => {
  if (!lista.length) return "<p style='color:#666;'>Sem notícias recentes sobre IA.</p>";
  return lista.map(n => `
    <div style="border:1px solid #fca5a5; border-radius:10px; padding:12px; margin-bottom:12px; background:#fef2f2; box-shadow:0 3px 8px rgba(0,0,0,0.08); transition: all 0.2s;">
      <strong style="font-size:16px; color:#991b1b;">${n.titulo}</strong><br>
      <a href="${n.link}" target="_blank" style="color:#dc2626; text-decoration:none; font-size:14px;">Ver fonte original 🔗</a>
    </div>
  `).join("");
};

// Ajuste para fuso de Brasília
const agora = new Date();
const horaBrasil = agora.getUTCHours() - 3;
const horaAjustada = (horaBrasil + 24) % 24;

// Determinar o período
let periodo = "";
if (horaAjustada >= 1 && horaAjustada < 12) periodo = "Manhã";
else if (horaAjustada >= 12 && horaAjustada < 17) periodo = "Tarde";
else periodo = "Noite";

// DEFINIR dataHoje para usar no cabeçalho e assunto
const dataHoje = agora.toLocaleDateString('pt-BR', {
  weekday: 'long',
  day: '2-digit',
  month: '2-digit'
});

// ------------------------
// CAPTURA O RESUMO ESTRUTURADO
// ------------------------
let resumoEstruturado = "";
if (todosOsItens[0] && todosOsItens[0].json.resumoEstruturado) {
  resumoEstruturado = todosOsItens[0].json.resumoEstruturado;
}

// 5. MONTAGEM DO HTML
const corpoFinal = `
<div style="background-color: #f4f7fb; padding: 20px 0; font-family: 'Helvetica Neue', Arial, sans-serif;">
  <div style="max-width: 700px; margin:auto; background:#ffffff; border-radius:12px; overflow:hidden; box-shadow:0 6px 15px rgba(0,0,0,0.1); border:1px solid #fecaca;">

    <!-- Header -->
    <div style="
      background-color:#dc2626;
      background:linear-gradient(90deg,#991b1b,#ef4444);
      padding:30px;
      text-align:center;
      border-bottom:4px solid #991b1b;
    ">
      <h1 style="margin:0; font-size:26px; letter-spacing:-0.5px; color:#fff;">
        Ronda IA – ${dataHoje} • ${periodo}
      </h1>
    </div>

    <div style="padding: 30px;">

      <!-- Intro -->
      <p style="font-size:15px; color:#333; line-height:1.6; margin-bottom:25px;">
        Olá, equipe! Este é o resumo sobre IA da ${periodo.toLowerCase()}, reunindo tendências de busca, dúvidas do público e notícias recentes sobre o assunto.
      </p>

      <!-- Resumo Estruturado -->
      <div style="margin-bottom:30px;">
        <h2 style="font-size:16px; font-weight:700; color:#991b1b; margin-bottom:12px;">
          Destaques
        </h2>
        <p style="font-size:15px; color:#333; line-height:1.6; margin-bottom:0;">
          ${resumoEstruturado}
        </p>
      </div>

      <!-- Trends -->
      <div style="margin-bottom:30px;">
        <h2 style="font-size:16px; font-weight:700; color:#991b1b; margin-bottom:12px;">
          Google Trends
        </h2>
        ${formatarLista(trends)}
      </div>

      <!-- PAA -->
      <div style="margin-bottom:30px;">
        <h2 style="font-size:16px; font-weight:700; color:#991b1b; margin-bottom:12px;">
          Pessoas também perguntam
        </h2>
        ${formatarLista(paa)}
      </div>

      <!-- Notícias -->
      <div style="margin-bottom:30px;">
        <h2 style="font-size:16px; font-weight:700; color:#991b1b; margin-bottom:12px;">
          Notícias sobre IA
        </h2>
        ${formatarNoticias(noticias)}
      </div>
    </div>

    <!-- Footer -->
    <div style="background:#fee2e2; padding:20px; text-align:center; border-top:1px solid #fca5a5; border-radius:0 0 12px 12px;">
      <p style="font-size:12px; color:#991b1b; margin:0;">
        Este resumo é gerado automaticamente com base em tendências e notícias recentes sobre IA.
      </p>
    </div>

  </div>
</div>
`;

// 6. RETORNO FINAL
return [{
  json: {
    corpoFinal,
    assunto: `Ronda IA 2026 - ${dataHoje} - ${periodo}`
  }
}];

// 1. TRAVA DE SEGURANÇA: roda apenas uma vez
if ($runIndex > 0) return [];

// 2. Inicializa arrays
const noticias = [];
const question = [];
const trends = [];

// 3. Separa os dados do Merge
const todosOsItens = $input.all();
todosOsItens.forEach(item => {
    const d = item.json;
    if (d.titulo) noticias.push(d);
    else if (d.question) question.push(d);
    else if (d.termo) trends.push(d);
});

// 4. Seleciona as principais tendências (até 3 termos)
const topTrends = trends.slice(0,3).map(t => t.termo).join(', ');

// 5. Seleciona as principais perguntas (até 3)
const topPAA = question.slice(0,3).map(q => q.question).join(', ');

// 6. Seleciona as 3 notícias mais relevantes (título apenas) e remove o sufixo do site
const topNoticias = noticias.slice(0,3).map(n => {
    let tituloLimpo = n.titulo;
    // Remove sufixo após " - ", se existir
    if(tituloLimpo.includes(' - ')){
        tituloLimpo = tituloLimpo.split(' - ')[0].trim();
    }
    return tituloLimpo;
});

// 7. Monta o parágrafo estruturado com highlights
let resumoEstruturado = `No topo do interesse do público pelo assunto aparecem ${topTrends.split(', ').map(t => `<strong>${t}</strong>`).join(', ')}. `;
if(topPAA) resumoEstruturado += `Enquanto isso, as dúvidas mais recorrentes se concentram em ${topPAA.split(', ').map(q => `<strong>${q}</strong>`).join(', ')}. `;
resumoEstruturado += ` Seguem abaixo as buscas e oportunidades detalhadas:`;

// 8. Retorno para o próximo nó (e-mail)
return [{
    json: {
        resumoEstruturado,
        trends: trends.map(t => t.termo),   // mantém array completo
        paa: question.map(q => q.question),       // mantém array completo
        noticias: noticias.map(n => {
            let tituloLimpo = n.titulo;
            if(tituloLimpo.includes(' - ')) tituloLimpo = tituloLimpo.split(' - ')[0].trim();
            return {
                titulo: tituloLimpo,
                link: n.link
            };
        })
    }
}];

const inputData = $input.item.json.data || [];
const MAX_AGE_HOURS = 24;
const IA_REGEX = /\b(ia|inteligência\s+artificial|artificial\s+intelligence|ai|openai|chatgpt|gpt-?4|gpt-?5|gemini|google\s+ai|claude|anthropic|copilot|microsoft\s+copilot|deepseek|grok|xai|llm|modelo\s+de\s+linguagem|modelo\s+generativo|ia\s+generativa|generative\s+ai|agente\s+de\s+ia|ai\s+agent|stable\s+diffusion|midjourney|runway|sora)\b/i;
const stopwords = ['do', 'da', 'de', 'dos', 'das', 'em', 'no', 'na', 'o', 'a', 'e', 'com', 'para', 'sobre', 'ao', 'à', 'as', 'os'];

// Função para limpar HTML e normalizar texto
const limparTexto = texto => {
  if (!texto) return '';
  return texto
    .replace(/<[^>]*>/g, '')
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ')
    .trim();
};

// Função para extrair palavras-chave relevantes
const extrairPalavrasChave = texto => {
  if (!texto) return [];
  return [...new Set(
    texto.toLowerCase()
      .replace(/[^a-z0-9\s]/gi, '')
      .split(/\s+/)
      .filter(w => w.length > 3 && !stopwords.includes(w))
  )];
};

// Função para gerar themeKey robusto (nomes próprios ou palavras-chave)
const gerarThemeKey = (titulo, resumo) => {
  const nomes = titulo.match(/\b[A-Z][a-z]+ [A-Z][a-z]+\b/g) || [];
  if (nomes.length) return nomes.join(' ');
  const palavras = extrairPalavrasChave(titulo).slice(0, 5);
  if (palavras.length) return palavras.join(' ');
  return (titulo + resumo).toLowerCase().slice(0, 30);
};


// PROCESSAMENTO
const finalSelection = [];
const seenThemes = new Set();

inputData.forEach(d => {
  const titulo = limparTexto(d.titulo || d.title || '');
  const resumo = limparTexto(d.resumo || d.description || '');
  const link = d.link || '';

  if (!titulo) return;

  const tituloLower = titulo.toLowerCase();

  if (!IA_REGEX.test(tituloLower)) return;

  const dataPublicacao = new Date(d.isoDate || d.pubDate || d.date || Date.now()).getTime();
  const ageHours = (Date.now() - dataPublicacao) / (1000 * 60 * 60);
  if (ageHours > MAX_AGE_HOURS) return;

  const themeKey = gerarThemeKey(titulo, resumo);
  if (seenThemes.has(themeKey)) return;

  // Score combina recência + click trigger
  let score = MAX_AGE_HOURS - ageHours;

  finalSelection.push({ titulo, resumo, link, themeKey, dataPublicacao, score });
  seenThemes.add(themeKey);
});

// Ordena por score (engajamento + recência)
finalSelection.sort((a, b) => b.score - a.score || b.dataPublicacao - a.dataPublicacao);

// Retorna até 7 notícias
return finalSelection.slice(0, 7).map(item => ({
  json: { titulo: item.titulo, link: item.link }
}));

return items.map(item => {
  const paa = item.json.related_questions || [];
  return paa.map(q => ({
    json: {
      question: q.question
    }
  }));
}).flat();
